import React from 'react';

const Navbar = ({ setView, userRole, logout, busqueda, handleBusquedaChange }) => {
  return (
    <nav className="sticky top-0 z-50 shadow-xl">
      <div className="bg-[#1e293b] text-white px-6 h-20 flex items-center justify-between gap-4">
        <div className="flex items-center gap-3 cursor-pointer shrink-0" onClick={() => setView('dashboard')}>
          <div className="bg-[#00c984] p-3 rounded-2xl shadow-lg shadow-green-500/20">
             <i className="fas fa-store text-[#1e293b] text-2xl"></i>
          </div>
          {/* Nombre de tu tienda más grande */}
          <h1 className="text-3xl font-black tracking-tighter uppercase">MI TIENDITA PRO</h1>
        </div>

        {/* Buscador más grande */}
        <div className="flex-1 max-w-2xl relative group hidden md:block">
          <input 
            type="text" 
            placeholder="Buscar productos por nombre..." 
            value={busqueda}
            onChange={handleBusquedaChange}
            className="w-full bg-[#334155] text-white py-3 px-6 pr-12 rounded-2xl text-lg outline-none focus:ring-4 focus:ring-[#00c984]/30 transition border border-slate-600"
          />
          <button className="absolute right-2 top-2 bg-[#00c984] text-[#1e293b] w-10 h-10 rounded-xl flex items-center justify-center">
            <i className="fas fa-search text-xl"></i>
          </button>
        </div>

        <div className="flex items-center gap-6 shrink-0">
          <div className="text-right hidden lg:block">
            <p className="text-xs font-bold text-slate-400 uppercase leading-none">Acceso: {userRole}</p>
          </div>
          <button onClick={logout} className="bg-red-500 text-white px-6 py-3 rounded-2xl text-sm font-black hover:bg-red-600 transition shadow-lg shadow-red-500/20 uppercase">
             Salir
          </button>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
